	.TITLE	RMIDI	.PROC	M680002	.REF	SMAKY	.LOC	0ONDMIDI:.BLKB	2		; no du driver MIDIONIMIDI:.BLKB	1		; 1 => driver MIDI pas install ici	.EVENOFLAGS:	.BLKB	1 BWAIT32 = 0	.EVENOLWAIT:	.BLKB	4OBMIDI:	.BLKB	1000LGVAR:	.LOC	0START:	LOAD.L	A6,#R16"VAR	LOAD.L	A4,A6	LOAD.W	D4,#LGVAR10$:	CLR.B	(A4+)	DEC.W	D4	JUMP,NE 10$15$:	LIB	?IFCAR	JUMP,EQ 15$	CALL	OPEMIDI	JUMP,NE ERFAT	NTREL	?GETPRIO	; D4 <-- priorit	DEC.W	D4	LOAD.L	D5,#600		; D5 <-- lg stack	LOAD.L	A5,#R16"PREAD	; A5 <-- ^start	LOAD.L	A3,#R16"NREAD	; A3 <-- ^nom	NTREL	?CRETASK	; dmarre la rception	LOAD.W	D4,D7	LIB	?AFX4	LIB	?AFCR20$:	LIB	?IFCAR	JUMP,EQ 70$	LOAD.L	A4,#(A6)+OBMIDI	LOAD.L	D4,#2+128	LOAD.W	D1,#TYPIO	LOAD.W	D2,(A6)+ONDMIDI	BIOS	?DRSTATUS	JUMP,NE 40$	ADD.L	A4,#2	CLR.W	D4	CLR.W	D330$:	TEST.B	(A4+)	JUMP,EQ 35$	LIB	?AFX2	LIB	?AFSPACE	INC.W	D335$:	INC.W	D4	COMP.W	D4,#128	JUMP,LO 30$	TEST.W	D3	JUMP,EQ 20$	LIB	?AFCR	JUMP	20$40$:	LOAD.W	D4,D7	LIB	?AFX4	LOAD.B	D3,#'*	LIB	?AFCAR	JUMP	20$70$:	CALL	STOPMIDI	CALL	CLOMIDI	EXITERFAT:	LIB	?AFTIM	.ASCIZ	"--ERREUR--"	.EVEN	EXIT;;;;;;;;;;;;;;;    WAIT    ;;;;;;;;;;;;;;;NREAD:	.ASCIZ	"MIDI_READ"	.EVENPREAD:	LOAD.L	D5,#-1	LOAD.W	D2,(A6)+ONDMIDI	BIOS	?DREAD	NTREL	?ABORT;--------\\; WRMIDI  >;========/; ; in	A4.L	^data; out	D7.W	erreur; mod	D7.WWRMIDI:	PUSHM.L	D2,D5	CLR.L	D5	LOAD.W	D5,(A4)	ADD.W	D5,#2	LOAD.W	D2,(A6)+ONDMIDI	BIOS	?DWRITE		; crit tout a	POPM.L	D2,D5	TEST.W	D7		; retour EQ/NE	RET;--------\\; COMMAND >;========/; Envoie une commande  MIDI.; in	A4.L	^commande; out	D7.W	erreur; mod	D7.WCOMMAND:	PUSHM.L	D1,D2	LOAD.W	D1,#TYPIO	; D1 <-- type	LOAD.W	D2,(A6)+ONDMIDI	BIOS	?DCOMMAND	POPM.L	D1,D2	TEST.W	D7		; retour EQ/NE	RET;---------\\; STOPMIDI >;=========/; Stoppe compltement MIDI.; in	-; out	-; mod	D7.WSTOPMIDI:	PUSH.L	D2	LOAD.W	D2,(A6)+ONDMIDI	BIOS	?DAVOTR		; avort lecture/criture;;?	NTREL	?WFABDESC	; attend la fin des processus fils	POP.L	D2	RET;--------\\; OPEMIDI >;========/; Ouvre le driver MIDI.; in	-; out	D7.W	erreur; mod	D7.WOPEMIDI:	PUSHM.L	D2,D3,A2..A4; Dinstalle l'usart en utilisant les noms #PR, #PP, #MI et #MO.	LOAD.L	A3,#R16"LUSART0	CLR.W	D3		; D3 <-- pour tous	FOS	?DEINSTALL	LOAD.L	A3,#R16"LUSART1;	CLR.W	D3		; D3 <-- pour tous	FOS	?DEINSTALL	LOAD.L	A3,#R16"LUSART2;	CLR.W	D3		; D3 <-- pour tous	FOS	?DEINSTALL	LOAD.L	A3,#R16"LUSART3;	CLR.W	D3		; D3 <-- pour tous	FOS	?DEINSTALL; Installe le driver MIDI  la place de l'usart.	CLR.B	(A6)+ONIMIDI	; driver MIDI install ici	LOAD.L	A3,#R16"LMIDI	; A3 <-- ^nom logique	LOAD.L	A4,#R16"PMIDI	; A4 <-- ^nom physique	LOAD.L	A2,#0		; A2 <-- ^paramtres;	CLR.W	D3		; D3 <-- pour tous	FOS	?INSTALL	; install le driver	JUMP,EQ 50$	COMP.W	D7,#ERUUSE	; dj install ?	JUMP,NE	90$		; non => 90$				; oui =>	SET.B	(A6)+ONIMIDI	; driver MIDI pas install ici50$:	LOAD.L	A3,#R16"DMIDI	FOS	?UNAMDRIV	; D2 <-- numro de driver	JUMP,NE	90$	LOAD.W	(A6)+ONDMIDI,D2	90$:	POPM.L	D2,D3,A2..A4	TEST.W	D7		; retour EQ/NE	RET;--------\\; CLOMIDI >;========/; Ferme le driver MIDI.; in	-; out	-; mod	D7.WCLOMIDI:	PUSHM.L	D3,A3	TEST.B	(A6)+ONIMIDI	; driver MIDI install ici ?	JUMP,T	90$		; non => 90$	LOAD.L	A3,#R16"LMIDI	; A3 <-- ^nom logique	CLR.W	D3		; D3 <-- pour tous	FOS	?DEINSTALL	; dinstall le driver90$:	POPM.L	D3,A3	RET; Textes; ------LUSART0:.ASCIZ	"#PR"LUSART1:.ASCIZ	"#PP"LUSART2:.ASCIZ	"#MI"LUSART3:.ASCIZ	"#MO"LMIDI:	.ASCIZ	"#MIDI:"PMIDI:	.ASCIZ	"$MIDI_0"DMIDI:	.ASCIZ	"MIDI_0"	.EVENVAR:	.FILLB	LGVAR,0	.END	START